  1→import React, { useEffect, useState, useCallback, useMemo } from "react";
  2→import './home.css'
  3→import { useAuth } from "../../Context/useAuth";
  4→import { useNavigate, Outlet, useLocation } from "react-router-dom";
  5→import Sidebar from "../SideBar/Sidebar";
  6→import { AnimatePresence, motion } from "framer-motion";
  7→
  8→import { useQueryClient } from '@tanstack/react-query';
  9→import Editor from "./Editor/Editor";
 10→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
 11→import MobileNavlink from "../mobileNavLink/MobileNavLink";
 12→import WriteJournalButton from "../WriteJournalButton/WriteJournalButton";
 13→import MobileSidebarLink from "../MobileSidebarLink/MobileSidebarLink";
 14→import OnboardingWizard from "../Onboarding/OnboardingWizard";
 15→import Loader from "../loadingComponent/BgLoader";
 16→import SidebarOpinions from "../SidebarOpinions/SidebarOpinions";
 17→import OpinionEditor from "../SidebarOpinions/OpinionsEditor";
 18→
 19→import { useMediaQuery } from 'react-responsive';
 20→
 21→const DEFAULT_EDITOR_LAUNCH_CONFIG = {
 22→    initialTitle: '',
 23→    promptId: null,
 24→    promptText: null,
 25→    draftId: null,
 26→    draftContent: null,
 27→};
 28→
 29→const HomePage = () => {
 30→    const {session, signOut, user, loading, isLoading, notifCount, openAuthModal} = useAuth();
 31→    const isGuest = !session && !loading;
 32→
 33→    const userId = user?.userData?.[0]?.id || null;
 34→
 35→    const isMobile = useMediaQuery({query: '(max-width: 480px)'});
 36→
 37→    const navigate = useNavigate();
 38→    const location = useLocation();
 39→
 40→    const queryClient = useQueryClient();
 41→    const [editor] = useLexicalComposerContext();
 42→
 43→    const [showMobileSideBar, setShowMobileSideBar] = useState(false);
 44→
 45→    const isOpinionsPage = location.pathname === '/home/opinions';
 46→    const isOpinionsViewer = location.pathname === '/home/opinionsViewer';
 47→
 48→    const navigatePath = useCallback((path) => {
 49→        if(window.location.pathname === path){
 50→           return window.location.reload()
 51→        }
 52→        return navigate(path);
 53→    }, [navigate])
 54→
 55→    const [showOnboarding, setShowOnboarding] = useState(false);
 56→    const [onboardingUserExists, setOnboardingUserExists] = useState(false);
 57→    const [showEditor, setShowEditor] = useState(false);
 58→    const [editorLaunchConfig, setEditorLaunchConfig] = useState(DEFAULT_EDITOR_LAUNCH_CONFIG);
 59→
 60→    const [showOpinionEditor, setShowOpinionEditor] = useState(false);
 61→
 62→    const handleOpenTextEditor = useCallback((config = {}) => {
 63→        editor.setEditable(true)
 64→        setEditorLaunchConfig({
 65→            ...DEFAULT_EDITOR_LAUNCH_CONFIG,
 66→            ...config
 67→        });
 68→        setShowEditor(true)
 69→    }, [editor])
 70→    const handleCloseEditor = useCallback(() => {
 71→        setShowEditor(false)
 72→        setEditorLaunchConfig(DEFAULT_EDITOR_LAUNCH_CONFIG);
 73→    }, [])
 74→
 75→    const links = useMemo(() => {
 76→        const activeColor = "#5f92ffff";
 77→        const inactiveColor = "#b6b6b6ff";
 78→        const pathname = location.pathname;
 79→
 80→        const homeLink = {
 81→            path: '/home',
 82→            label: 'Home',
 83→            action: ()=> navigatePath('/home'),
 84→            icon:
 85→            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
 86→                <g id="style=fill">
 87→                    <g id="home-line" clipPath="url(#clip0_1_110)">
 88→                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M14.3594 2.12613C13.0087 0.944612 10.9923 0.94461 9.64162 2.12612L3.2802 7.69086C2.29508 8.55261 1.72998 9.79772 1.72998 11.1066L1.72998 19.1672C1.72998 21.1459 3.33403 22.75 5.31273 22.75L18.6883 22.75C20.667 22.75 22.271 21.1459 22.271 19.1672L22.271 11.1066C22.271 9.79772 21.706 8.55261 20.7208 7.69086L14.3594 2.12613ZM10 16.1136C9.58579 16.1136 9.25 16.4494 9.25 16.8636C9.25 17.2779 9.58579 17.6136 10 17.6136L14 17.6136C14.4142 17.6136 14.75 17.2779 14.75 16.8636C14.75 16.4494 14.4142 16.1136 14 16.1136L10 16.1136Z" fill={pathname === '/home' ? activeColor : inactiveColor}/>
 89→                    </g>
 90→                </g>
 91→            </svg>
 92→        };
 93→
 94→        const exploreLink = {
 95→            path: '/home/explore',
 96→            label: 'Explore',
 97→            action: () => navigatePath('/home/explore'),
 98→            icon:
 99→            <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000">
100→                <path fillRule="evenodd" d="M12,2 C17.5228475,2 22,6.4771525 22,12 C22,17.5228475 17.5228475,22 12,22 C6.4771525,22 2,17.5228475 2,12 C2,6.4771525 6.4771525,2 12,2 Z M17.9842695,7.39078625 C18.1985588,6.64477525 17.4973604,5.9435768 16.7513494,6.1578661 L16.6494246,6.19284365 L9.57835679,9.02127078 L9.47282273,9.07079854 C9.30957453,9.15937167 9.17428758,9.29167162 9.08209683,9.45256344 L9.02127078,9.57835679 L6.19284365,16.6494246 L6.1578661,16.7513494 C5.9435768,17.4973604 6.64477525,18.1985588 7.39078625,17.9842695 L7.49271102,17.949292 L14.5637788,15.1208648 L14.6693129,15.0713371 C14.8325611,14.982764 14.967848,14.850464 15.0600388,14.6895722 L15.1208648,14.5637788 L17.949292,7.49271102 L17.9842695,7.39078625 Z M12,10 C13.1045695,10 14,10.8954305 14,12 C14,13.1045695 13.1045695,14 12,14 C10.8954305,14 10,13.1045695 10,12 C10,10.8954305 10.8954305,10 12,10 Z" fill={pathname === '/home/explore' ? activeColor : inactiveColor} />
101→            </svg>
102→        };
103→
104→        if (isGuest) {
105→            return [homeLink, exploreLink,
106→                { label: 'Log in', action: () => navigate('/login'), className: 'write-journal-bttn' },
107→                { label: 'Sign up', action: () => navigate('/signUp'), className: 'sidebar-links' },
108→            ];
109→        }
110→
111→        return [homeLink, exploreLink,
112→            {
113→                path: '/profile',
114→                label: 'Profile', action: ()=> navigatePath('/profile'),
115→                icon:
116→                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
117→                    <g id="style=fill">
118→                        <g id="profile">
119→                            <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M6.75 6.5C6.75 3.6005 9.1005 1.25 12 1.25C14.8995 1.25 17.25 3.6005 17.25 6.5C17.25 9.3995 14.8995 11.75 12 11.75C9.1005 11.75 6.75 9.3995 6.75 6.5Z" fill={pathname === '/profile' ? activeColor : inactiveColor}/>
120→                            <path id="rec (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M4.25 18.5714C4.25 15.6325 6.63249 13.25 9.57143 13.25H14.4286C17.3675 13.25 19.75 15.6325 19.75 18.5714C19.75 20.8792 17.8792 22.75 15.5714 22.75H8.42857C6.12081 22.75 4.25 20.8792 4.25 18.5714Z" fill={pathname === '/profile' ? activeColor : inactiveColor}/>
121→                        </g>
122→                    </g>
123→                </svg>
124→            },
125→            {
126→                path: '/home/notifications',
127→                label: 'Notifications',
128→                notifCount: notifCount > 0 ? notifCount : '',
129→                action: () => navigate('/home/notifications'),
130→                icon:
131→                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="#000000ff">
132→                    <g id="style=fill">
133→                        <g id="notification-bell">
134→                            <path id="vector (Stroke)" fillRule="evenodd" clipRule="evenodd" d="M14.802 19.8317C15.4184 19.7699 15.8349 20.4242 15.5437 20.9539C15.3385 21.3271 15.0493 21.6529 14.7029 21.9197C14.3496 22.1918 13.9397 22.4006 13.5 22.5408C13.0601 22.6812 12.593 22.7522 12.1242 22.7522C11.6554 22.7522 11.1883 22.6812 10.7484 22.5408C10.3087 22.4006 9.89883 22.1918 9.54556 21.9197C9.1991 21.6529 8.90988 21.3271 8.70472 20.9539C8.41354 20.4242 8.83002 19.7699 9.44644 19.8317C9.63869 19.851 11.1433 19.9981 12.1242 19.9981C13.1051 19.9981 14.6097 19.851 14.802 19.8317Z" fill={pathname === '/home/notifications' ? activeColor : inactiveColor}/>
135→                            <path id="vector (Stroke)_2" fillRule="evenodd" clipRule="evenodd" d="M8.52901 2.08755C10.7932 1.00445 13.4465 0.967602 15.7423 1.98737L15.9475 2.07851C18.3532 3.14707 19.8934 5.4622 19.8934 8.0096L19.8934 9.27297C19.8934 10.2885 20.1236 11.2918 20.5681 12.213L20.8335 12.7632C22.0525 15.29 20.465 18.2435 17.6156 18.7498L17.455 18.7783C13.93 19.4046 10.3154 19.4046 6.79044 18.7783C3.90274 18.2653 2.37502 15.1943 3.77239 12.7115L3.99943 12.3082C4.55987 11.3124 4.85335 10.1981 4.85335 9.06596L4.85335 7.79233C4.85335 5.3744 6.27704 3.16478 8.52901 2.08755Z" fill={pathname === '/home/notifications' ? activeColor : inactiveColor}/>
136→                        </g>
137→                    </g>
138→                </svg>
139→            },
140→            {
141→                path: '/home/bookmark',
142→                label: 'Bookmarks',
143→                action: ()=> navigatePath('/home/bookmark'),
144→                icon:
145→                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill="none">
146→                    <g id="style=fill">
147→                        <g id="bookmark">
148→                        <path id="Subtract" fillRule="evenodd" clipRule="evenodd" d="M8 1.25C5.37665 1.25 3.25 3.37665 3.25 6V20.4648C3.25 21.7269 4.27311 22.75 5.53518 22.75C5.98634 22.75 6.42739 22.6165 6.80278 22.3662L11.3066 19.3636C11.7265 19.0837 12.2735 19.0837 12.6934 19.3636L17.1972 22.3662C17.5726 22.6165 18.0137 22.75 18.4648 22.75C19.7269 22.75 20.75 21.7269 20.75 20.4648V6C20.75 3.37665 18.6234 1.25 16 1.25H8ZM9 6.75C8.58579 6.75 8.25 7.08579 8.25 7.5C8.25 7.91421 8.58579 8.25 9 8.25H15C15.4142 8.25 15.75 7.91421 15.75 7.5C15.75 7.08579 15.4142 6.75 15 6.75H9Z" fill={pathname === '/home/bookmark' ? activeColor : inactiveColor}/>
149→                        </g>
150→                    </g>
151→                </svg>
152→            },
153→            {
154→                path: '/home/drafts',
155→                label: 'Drafts',
156→                action: () => navigatePath('/home/drafts'),
157→                icon:
158→                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/drafts' ? activeColor : inactiveColor}>
159→                    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8l-6-6z"/>
160→                    <polyline points="14 2 14 8 20 8" fill="none" stroke={pathname === '/home/drafts' ? activeColor : inactiveColor} strokeWidth="1"/>
161→                    <line x1="16" y1="13" x2="8" y2="13" stroke={pathname === '/home/drafts' ? '#fff' : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
162→                    <line x1="16" y1="17" x2="8" y2="17" stroke={pathname === '/home/drafts' ? '#fff' : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
163→                </svg>
164→            },
165→            {
166→                path: '/home/analytics',
167→                label: 'Analytics',
168→                action: () => navigatePath('/home/analytics'),
169→                icon:
170→                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/analytics' ? activeColor : inactiveColor}>
171→                    <path d="M3 3v18h18" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
172→                    <path d="M7 17V13" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
173→                    <path d="M11 17V9" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
174→                    <path d="M15 17V5" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
175→                    <path d="M19 17V11" stroke={pathname === '/home/analytics' ? activeColor : inactiveColor} strokeWidth="2" strokeLinecap="round"/>
176→                </svg>
177→            },
178→            {
179→                path: '/home/settings',
180→                label: 'Settings',
181→                action: () => navigatePath('/home/settings'),
182→                icon:
183→                <svg xmlns="http://www.w3.org/2000/svg" width="28px" height="28px" viewBox="0 0 24 24" fill={pathname === '/home/settings' ? "#5f92ff" : "#b6b6b6"}>
184→                    <path d="M12 15.5A3.5 3.5 0 1 0 12 8.5a3.5 3.5 0 0 0 0 7Z"/>
185→                    <path d="M19.43 12.98c.04-.32.07-.64.07-.98 0-.34-.03-.66-.07-.98l2.11-1.65a.5.5 0 0 0 .12-.64l-2-3.46a.5.5 0 0 0-.61-.22l-2.49 1a7.04 7.04 0 0 0-1.69-.98l-.38-2.65A.49.49 0 0 0 14 2h-4a.49.49 0 0 0-.49.42l-.38 2.65c-.61.25-1.17.59-1.69.98l-2.49-1a.5.5 0 0 0-.61.22l-2 3.46a.49.49 0 0 0 .12.64l2.11 1.65c-.04.32-.07.65-.07.98 0 .33.03.66.07.98l-2.11 1.65a.5.5 0 0 0-.12.64l2 3.46c.12.22.39.3.61.22l2.49-1c.52.4 1.08.73 1.69.98l.38 2.65c.05.24.26.42.49.42h4c.24 0 .44-.18.49-.42l.38-2.65c.61-.25 1.17-.59 1.69-.98l2.49 1c.23.09.49 0 .61-.22l2-3.46a.5.5 0 0 0-.12-.64l-2.11-1.65Z"/>
186→                </svg>
187→            },
188→            {
189→                label: 'Write', action: () => handleOpenTextEditor(),
190→                className: 'write-journal-bttn'
191→            },
192→        ];
193→    }, [location.pathname, isGuest, notifCount, navigate, navigatePath, handleOpenTextEditor]);
194→
195→    const handleOnboardingComplete = useCallback((action) => {
196→        setShowOnboarding(false);
197→        queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
198→        if (action === 'write') {
199→            handleOpenTextEditor();
200→        } else if (action === 'story') {
201→            navigate('/home/stories/new');
202→        }
203→        // 'explore' → just close, user lands on feed
204→    }, [queryClient, session, handleOpenTextEditor, navigate]);
205→
206→    const handleClickMobileProfileLink = () =>{
207→        setShowMobileSideBar(true)
208→    }
209→    const handleClickCloseSidebar = () =>{
210→        setShowMobileSideBar(false)
211→    }
212→
213→    const handleOpenOpinionTextEditor = () =>{
214→        setShowOpinionEditor(true)
215→    }
216→    const handleCloseOpiniionTextEditor = () =>{
217→        setShowOpinionEditor(false);
218→    }
219→
220→    useEffect(() => {
221→        const launchState = location.state;
222→        if(!launchState?.openEditor){
223→            return;
224→        }
225→
226→        handleOpenTextEditor({
227→            initialTitle: launchState?.initialTitle || ''
228→        });
229→
230→        navigate(location.pathname, {replace: true, state: null});
231→    }, [location.state, location.pathname, navigate, handleOpenTextEditor]);
232→
233→    //handle show links header when stop scrolling and hides header when scrolling
234→    // useEffect(() =>{
235→    //     const handleScroll = (e) => {
236→    //         clearTimeout(scrollRefTimeOut.current)
237→    //         setShowHeaders(false)
238→
239→    //         scrollRefTimeOut.current = setTimeout(() => {
240→    //             setShowHeaders(true)
241→    //         }, 500);
242→    //     }
243→        
244→    //     document.addEventListener('scroll', handleScroll, true);
245→
246→    //     return() => {
247→    //         document.removeEventListener('scroll', handleScroll, true);
248→    //         clearTimeout(scrollRefTimeOut.current)
249→    //     }
250→    // }, [])
251→
252→    useEffect(() => {
253→        if(session && !loading && user){
254→            const profileData = user?.userData?.[0];
255→            const exists = !!profileData;
256→            const onboarded = profileData?.onboarding_completed ?? true;
257→            if(!exists || !onboarded){
258→                setOnboardingUserExists(exists);
259→                setShowOnboarding(true);
260→            }
261→        }
262→    },[session, loading, user])
263→
264→    
265→
266→    if(isLoading && !isGuest){
267→        return(
268→            <Loader/>
269→        )
270→    }
271→
272→    return(
273→        <>
274→        {!isGuest && showOnboarding && (
275→            <OnboardingWizard
276→                onComplete={handleOnboardingComplete}
277→                userExists={onboardingUserExists}
278→            />
279→        )}
280→
281→        <AnimatePresence>
282→        {!isGuest && showEditor && (
283→            <Editor
284→                key={'main-editor'}
285→                onClose={handleCloseEditor}
286→                initialTitle={editorLaunchConfig.initialTitle}
287→                promptId={editorLaunchConfig.promptId}
288→                promptText={editorLaunchConfig.promptText}
289→                draftId={editorLaunchConfig.draftId}
290→                draftContent={editorLaunchConfig.draftContent}
291→            />
292→        )}
293→
294→        {!isGuest && showOpinionEditor && (
295→            <OpinionEditor onClose={handleCloseOpiniionTextEditor}/>
296→        )}
297→
298→        </AnimatePresence>
299→        
300→        <div className="home-parent-container">
301→             <div className="side-bar-holder-container">
302→                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
303→            </div>
304→            <div id="main-content" className="center-bar-holder-container">
305→
306→                {/* <AnimatePresence>
307→                {showHeaders && (
308→                    <motion.div 
309→                    className="newsfeed-header"
310→                    initial={{opacity: 0}}
311→                    animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
312→                    exit={{ opacity: 0, y: -20,
313→                        transition: { 
314→                            duration: 0.2,
315→                            ease: "easeOut"
316→                        }
317→                    }}
318→                    >
319→                        {header_links.map((header_link, index) => (
320→                            <div key={index} className="header-links">
321→                                {header_link.label}
322→                            </div>
323→                        ))}
324→                    </motion.div>
325→                )}
326→                </AnimatePresence> */}
327→
328→                <AnimatePresence mode="wait">
329→                    <motion.div
330→                        key={location.pathname}
331→                        initial={{ opacity: 0, y: 8 }}
332→                        animate={{ opacity: 1, y: 0 }}
333→                        exit={{ opacity: 0 }}
334→                        transition={{ duration: 0.2, ease: [0.25, 1, 0.5, 1] }}
335→                    >
336→                        <Outlet context={{ clickOpenSidebar: handleClickMobileProfileLink, handleOpenTextEditor }} />
337→                    </motion.div>
338→                </AnimatePresence>
339→            </div>
340→            <div className="sidebar-right-holder-container">
341→                {/* Log out */}
342→                {!isMobile && !isOpinionsViewer &&(
343→                    <SidebarOpinions openEditor={handleOpenOpinionTextEditor}/>
344→                )}
345→                
346→            </div>
347→            
348→            {!isGuest && !isOpinionsPage && !isOpinionsViewer && (
349→                <WriteJournalButton onOpen={handleOpenTextEditor} hideOnHomeFeed={location.pathname === '/home' || location.pathname === '/home/opinions'}/>
350→            )}
351→            
352→            <MobileNavlink />
353→        </div>
354→        
355→        {showMobileSideBar && (
356→            <MobileSidebarLink onclose={handleClickCloseSidebar}/>
357→        )}
358→        </>
359→    )
360→}
361→export default HomePage
