    position: fixed;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 250px;
    height: 100%;
    border-right: 0.7px solid var(--border-light);
    z-index: 2;
}
.center-bar-holder-container{
    position: relative;
    align-items: center;
    left: 250px;
    display: flex;
    flex-direction: column;
    width: 750px;
    height: 100vh;
}
.sidebar-right-holder-container{
    position: fixed;
    left: 1000px;
    display: flex;
    justify-content: center;
    align-items: flex-start;
    width: 27%;
    height: 100%;
    border-left: 0.7px solid var(--border-light);
}
@keyframes profileSlideUp {
    from { opacity: 0; transform: translateY(16px); }
    to   { opacity: 1; transform: translateY(0); }
}
